import{c as a,Q as s,j as t,m as r}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Features, embeddings, and tags","description":"","frontmatter":{},"headers":[],"relativePath":"ru/concepts/features-embeddings-tags.md","filePath":"ru/concepts/features-embeddings-tags.md","lastUpdated":null}'),i={name:"ru/concepts/features-embeddings-tags.md"};function d(n,e,l,o,c,p){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="features-embeddings-and-tags" tabindex="-1">Features, embeddings, and tags <a class="header-anchor" href="#features-embeddings-and-tags" aria-label="Permalink to &quot;Features, embeddings, and tags&quot;">​</a></h1><p>Аудитория: пользователи, сравнивающие analysis families<br> Цель: четко разделить data types проекта<br> Тип: explanation</p><p>App хранит несколько видов информации. В UI они могут выглядеть похожими, но не являются взаимозаменяемыми.</p><h2 id="file-tags" tabindex="-1">File tags <a class="header-anchor" href="#file-tags" aria-label="Permalink to &quot;File tags&quot;">​</a></h2><p>Tags приходят из audio file metadata: title, artist, album, BPM, key и другие human-facing fields. Scan and RefreshTags читают практический whitelist в SQLite.</p><p>Для Smart Set Builder tag BPM preferred when present. SONARA BPM - fallback.</p><h2 id="sonara-features" tabindex="-1">SONARA features <a class="header-anchor" href="#sonara-features" aria-label="Permalink to &quot;SONARA features&quot;">​</a></h2><p>SONARA пишет feature values, model metadata и derived working fields вроде BPM, key, duration, energy в SQLite. Это analyzed values, а не file tags, записанные обратно в audio.</p><h2 id="embeddings" tabindex="-1">Embeddings <a class="header-anchor" href="#embeddings" aria-label="Permalink to &quot;Embeddings&quot;">​</a></h2><p>MERT, CLAP и MAEST хранят vector embeddings в SQLite. Search и SET могут использовать эти vectors как similarity signals.</p><p>MAEST также производит genre analysis, но SET selection не должен опираться на MAEST genre labels. MAEST embeddings - другой signal.</p><h2 id="classifier-scores" tabindex="-1">Classifier scores <a class="header-anchor" href="#classifier-scores" aria-label="Permalink to &quot;Classifier scores&quot;">​</a></h2><p>Promoted classifier profiles пишут scores в <code>track_classifier_scores</code>. Score принадлежит одному classifier key. Missing classifier scores нейтральны для SET.</p><h2 id="reports-and-exports" tabindex="-1">Reports and exports <a class="header-anchor" href="#reports-and-exports" aria-label="Permalink to &quot;Reports and exports&quot;">​</a></h2><p>Reports, playlists и helper-tool output - local files. Это не то же самое, что library state, и обычно может быть regenerated.</p>',15)])])}const g=a(i,[["render",d]]);export{u as __pageData,g as default};
